type PostStudioGenerateRequest struct {
	Prompt         string           `json:"prompt" binding:"required"`
	Agent          string           `json:"agent"`
	Provider       string           `json:"provider"`
	Model          string           `json:"model"`
	ConversationID string           `json:"conversation_id"`
	ExistingFiles  []GeneratedFile  `json:"existing_files"`
}

func PostStudioGenerate(c *gin.Context) {
	var req PostStudioGenerateRequest
	if err := c.ShouldBindJSON(&req); err != nil {
		c.JSON(http.StatusBadRequest, gin.H{"error": err.Error()})
		return
	}
	agent := strings.ToLower(strings.TrimSpace(req.Agent))
	if agent == "" {
		agent = "coding"
	}
	if len(req.ExistingFiles) > 0 {
		agent = "build"
	}
	userMsg := req.Prompt
	if agent == "build" {
		userMsg = buildEditAwareUserMessage(req.Prompt, req.ExistingFiles)
	}
	provider := inferProviderFromModel(req.Model)
	resp, err := llm.Chat(c.Request.Context(), provider, req.Model, agent, userMsg)
	if err != nil {
		applog.Errorf("studio generate: %v", err)
		c.JSON(http.StatusBadGateway, gin.H{"error": "llm call failed"})
		return
	}
	summary, code := extractSummaryAndCode(resp)
	code = sanitizeBuildResponse(code)
	c.JSON(http.StatusOK, gin.H{
		"response":       code,
		"summary":        summary,
		"conversation_id": req.ConversationID,
		"agent":          agent,
		"provider":       provider,
	})
}

func PushStudioToRepo(c *gin.Context) {
	var req struct {
		StoragePath   string `json:"storage_path" binding:"required"`
		RepoURL       string `json:"repo_url" binding:"required"`
		Branch        string `json:"branch"`
		CommitMessage string `json:"commit_message"`
		Provider      string `json:"provider"`
	}
	if err := c.ShouldBindJSON(&req); err != nil {
		c.JSON(http.StatusBadRequest, gin.H{"error": err.Error()})
		return
	}
	root, ok := ensurePathUnderRoot(req.StoragePath, ".")
	if !ok {
		c.JSON(http.StatusBadRequest, gin.H{"error": "invalid storage_path"})
		return
	}
	if req.Branch == "" {
		req.Branch = "main"
	}
	if req.CommitMessage == "" {
		req.CommitMessage = "chore: push from studio"
	}
	cred, err := core.GetGitCredential(c.Request.Context(), req.Provider)
	if err != nil {
		c.JSON(http.StatusForbidden, gin.H{"error": "not authenticated with " + req.Provider})
		return
	}
	if err := core.GitInitCommitPush(root, cred, req.RepoURL, req.Branch, req.CommitMessage); err != nil {
		applog.Errorf("git push: %v", err)
		c.JSON(http.StatusBadGateway, gin.H{"error": err.Error()})
		return
	}
	c.JSON(http.StatusOK, gin.H{"status": "pushed", "branch": req.Branch})
}

func HandleDevServerReady(c *gin.Context) {
	storagePath := c.Query("storage_path")
	port, _ := strconv.Atoi(c.Query("port"))
	if storagePath == "" || port <= 0 {
		c.JSON(http.StatusBadRequest, gin.H{"error": "storage_path and port are required"})
		return
	}
	c.Header("Content-Type", "text/event-stream")
	c.Header("Cache-Control", "no-cache")
	c.Header("X-Accel-Buffering", "no")
	ctx := c.Request.Context()
	ticker := time.NewTicker(1 * time.Second)
	defer ticker.Stop()
	deadline := time.After(120 * time.Second)
	for {
		select {
		case <-ctx.Done():
			return
		case <-deadline:
			fmt.Fprintf(c.Writer, "event: error\ndata: %s\n\n", "timeout")
			c.Writer.Flush()
			return
		case <-ticker.C:
			resp, err := http.Get(fmt.Sprintf("http://127.0.0.1:%d", port))
			if err == nil && resp.StatusCode < 500 {
				resp.Body.Close()
				fmt.Fprintf(c.Writer, "event: ready\ndata: %d\n\n", port)
				c.Writer.Flush()
				return
			}
			if resp != nil {
				resp.Body.Close()
			}
			fmt.Fprintf(c.Writer, "event: status\ndata: starting\n\n")
			c.Writer.Flush()
		}
	}
}

