export function inferLanguageFromPath(path: string): string {
  const dot = path.lastIndexOf('.');
  if (dot < 0) return 'plaintext';
  return EXT_TO_LANGUAGE[path.slice(dot + 1).toLowerCase()] ?? 'plaintext';
}

export async function fetchWithTimeout(url: string, opts: RequestInit = {}, ms = 30_000): Promise<Response> {
  const c = new AbortController();
  const id = setTimeout(() => c.abort(), ms);
  try {
    return await fetch(url, { ...opts, signal: c.signal });
  } finally {
    clearTimeout(id);
  }
}

export function slugify(s: string): string {
  return s.toLowerCase().replace(/[^a-z0-9]+/g, '-').replace(/^-+|-+$/g, '');
}

export function truncate(s: string, n: number): string {
  return s.length <= n ? s : s.slice(0, n - 1) + '…';
}

export function clamp(n: number, min: number, max: number): number {
  return Math.min(max, Math.max(min, n));
}

export function safeParseJSON<T=unknown>(raw: string): T | null {
  try { return JSON.parse(raw) as T; } catch { return null; }
}

export function uniq<T>(xs: readonly T[]): T[] {
  const seen = new Set<T>();
  const out: T[] = [];
  for (const x of xs) if (!seen.has(x)) { seen.add(x); out.push(x); }
  return out;
}

export function bySlug<T extends { slug: string }>(xs: readonly T[]): Record<string, T> {
  const out: Record<string, T> = {};
  for (const x of xs) out[x.slug] = x;
  return out;
}

export function ensureTrailingSlash(s: string): string {
  return s.endsWith('/') ? s : s + '/';
}

export function relTime(ts: number | Date): string {
  const t = typeof ts === 'number' ? ts : ts.getTime();
  const d = Math.floor((Date.now() - t) / 1000);
  if (d < 60) return `${d}s ago`;
  if (d < 3600) return `${Math.floor(d/60)}m ago`;
  if (d < 86400) return `${Math.floor(d/3600)}h ago`;
  return `${Math.floor(d/86400)}d ago`;
}

export function parseCookie(raw: string): Record<string,string> {
  const out: Record<string,string> = {};
  for (const part of raw.split('; ')) {
    const idx = part.indexOf('=');
    if (idx > 0) out[part.slice(0, idx)] = decodeURIComponent(part.slice(idx + 1));
  }
  return out;
}

