def flatten(d: dict, parent: str = '', sep: str = '.') -> dict:
    out: dict = {}
    for k, v in d.items():
        nk = f'{parent}{sep}{k}' if parent else k
        if isinstance(v, dict):
            out.update(flatten(v, nk, sep))
        else:
            out[nk] = v
    return out

